#include <stdio.h>
#include <stdlib.h>
#define MAX_N 5000
#define MAX_K 5000
int dp[MAX_N + 1][MAX_K + 1];
int A[MAX_N + 1];
int max(int a, int b) { return a > b ? a : b; }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, D, M;
        scanf("%d %d %d %d", &N, &K, &D, &M);
        for (int i = 1; i <= N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = -1;
            }
        }
        printf("%d\n", solve(N, K, D, M, A));
    }
    return 0;
}
int solve(int N, int K, int D, int M, int A[]) {
    if (K < 0 || N < 0) return -1;
    if (K == 0 && N == 0) return 0;
    if (dp[N][K] != -1) return dp[N][K];
    int ans = -1;
    if (K > 0) {
        ans = max(ans, solve(N - 1, K - 1, D, M, A));
    }
    if (N > 0) {
        int last_break = N - 1;
        while (last_break >= 0 && last_break >= N - D) {
            if (K > 0 && last_break > 0 && A[last_break] != 0) {
                ans = max(ans, solve(last_break - 1, K - 1, D, M, A) + M * A[N]);
            } else {
                ans = max(ans, solve(last_break, K, D, M, A) + A[N]);
            }
            last_break--;
        }
    }
    return dp[N][K] = ans;
}

