const MAX_N = 5000;
const MAX_K = 5000;
const dp = Array(MAX_N + 1).fill(0).map(() => Array(MAX_K + 1).fill(-1));
const A = Array(MAX_N + 1).fill(0);
function solve(N, K, D, M, A) {
    if (K < 0 || N < 0) return -1;
    if (K == 0 && N == 0) return 0;
    if (dp[N][K] != -1) return dp[N][K];
    let ans = -1;
    if (K > 0) {
        ans = Math.max(ans, solve(N - 1, K - 1, D, M, A));
    }
    if (N > 0) {
        let last_break = N - 1;
        while (last_break >= 0 && last_break >= N - D) {
            if (K > 0 && last_break > 0 && A[last_break] != 0) {
                ans = Math.max(ans, solve(last_break - 1, K - 1, D, M, A) + M * A[N]);
            } else {
                ans = Math.max(ans, solve(last_break, K, D, M, A) + A[N]);
            }
            last_break--;
        }
    }
    return dp[N][K] = ans;
}
let T = +input();
while (T-- > 0) {
    let [N, K, D, M] = input().split(' ').map(Number);
